import React, { useEffect } from 'react';

const ReloadPageComponent = () => {
  useEffect(() => {
    const reloadPage = () => {
      setTimeout(() => {
        window.location.reload();
      }, 3000); // 3000 milliseconds = 3 seconds
    };

        reloadPage(); // Call the function to reload the page after component mounts

        // Note: Since this effect has no dependencies, it runs only once after the component mounts
    }, []);

    return (
        <div>
            <h1>Page will reload in 3 seconds...</h1>
            {/* You can add more content here if needed */}
        </div>
    );
};

export default ReloadPageComponent;
